import React, { useEffect, useState } from "react";

// ================= PARENT COMPONENT =================
function AssignmentApp({ userId }) {
  const [assignments, setAssignments] = useState([]);
  const [message, setMessage] = useState("");

  // Fetch assignments from backend
  const fetchAssignments = async () => {
    try {
      const response = await fetch(`http://localhost:8080/assignments/user/${userId}`);
      const data = await response.json();
      setAssignments(data);
    } catch (error) {
      console.error("Error fetching assignments:", error);
    }
  };

  useEffect(() => {
    fetchAssignments();
  }, []);

  return (
    <div>
      <AssignmentList
        assignments={assignments}
        setAssignments={setAssignments}
        setMessage={setMessage}
      />
      {message && <div className="message">{message}</div>}
    </div>
  );
}

// ================= CHILD COMPONENT =================
function AssignmentList({ assignments, setAssignments, setMessage }) {

  // ================= DELETE FUNCTION =================
  const deleteAssignment = async (id) => {
    const confirmDelete = window.confirm(
      "⚠️ Are you sure you want to delete this assignment?"
    );
    if (!confirmDelete) return;

    try {
      const response = await fetch(`http://localhost:8080/assignments/delete/${id}`, {
        method: "DELETE",
      });

      if (response.ok) {
        setAssignments(prev => prev.filter(a => a.id !== id)); // Remove deleted assignment
        setMessage("✅ Assignment deleted successfully!");
        setTimeout(() => setMessage(""), 3000);
      } else {
        alert("Failed to delete assignment");
      }
    } catch (error) {
      console.error(error);
    }
  };

  // ================= SUBMIT FUNCTION =================
  const submitAssignment = async (id) => {
    try {
      const response = await fetch(`http://localhost:8080/assignments/submit/${id}`, {
        method: "PUT",
      });

      if (response.ok) {
        // Update assignment status in local state
        setAssignments(prev =>
          prev.map(a =>
            a.id === id ? { ...a, status: "Submitted" } : a
          )
        );
        setMessage("✅ Assignment submitted successfully!");
        setTimeout(() => setMessage(""), 3000);
      } else {
        alert("Failed to submit assignment");
      }
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div className="card">
      <h2>Assignments</h2>

      <ul>
        {/* Header Row */}
        <li className="assignment-header">
          <span>Title</span>
          <span>Subject</span>
          <span>Due Date</span>
          <span>Status</span>
          <span>Action</span>
        </li>

        {/* Assignment Rows */}
        {assignments.map((assignment) => (
          <li key={assignment.id}>
            <span>{assignment.title}</span>
            <span>{assignment.subject}</span>
            <span>{assignment.dueDate}</span>

            <span
              className={`status ${
                assignment.status === "Pending" ? "pending" : "submitted"
              }`}
            >
              {assignment.status}
            </span>

            <span>
              {assignment.status === "Pending" && (
                <button onClick={() => submitAssignment(assignment.id)}>
                  Submit
                </button>
              )}

              <button
                style={{ backgroundColor: "#ef4444", marginLeft: "8px" }}
                onClick={() => deleteAssignment(assignment.id)}
              >
                Delete
              </button>
            </span>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default AssignmentApp;
